import json
import boto3
import os
import re
from typing import Dict, Any, List

sns_client = boto3.client('sns')

ALLOWED_TOPIC_ARNS = os.environ.get('ALLOWED_TOPIC_ARNS', '').split(',')
ALLOWED_TOPIC_ARNS = [arn.strip() for arn in ALLOWED_TOPIC_ARNS if arn.strip()]

MAX_MESSAGE_SIZE = 256 * 1024
MAX_SUBJECT_LENGTH = 100

NOTIFICATION_TYPES = {
    'alert': {
        'subject_prefix': '[ALERT]',
        'required_fields': ['message', 'severity']
    },
    'info': {
        'subject_prefix': '[INFO]',
        'required_fields': ['message']
    },
    'warning': {
        'subject_prefix': '[WARNING]',
        'required_fields': ['message', 'source']
    },
    'error': {
        'subject_prefix': '[ERROR]',
        'required_fields': ['message', 'error_code']
    }
}

def validate_topic_arn(topic_arn: str) -> bool:
    if not topic_arn:
        return False
    
    arn_pattern = r'^arn:aws:sns:[a-z0-9-]+:\d{12}:[a-zA-Z0-9_-]+$'
    if not re.match(arn_pattern, topic_arn):
        return False
    
    if not ALLOWED_TOPIC_ARNS:
        return False
    
    return topic_arn in ALLOWED_TOPIC_ARNS

def validate_notification_type(notification_type: str) -> bool:
    return notification_type in NOTIFICATION_TYPES

def validate_message_content(message: str) -> bool:
    if not message or not isinstance(message, str):
        return False
    
    if len(message.encode('utf-8')) > MAX_MESSAGE_SIZE:
        return False
    
    return True

def validate_subject(subject: str) -> bool:
    if not isinstance(subject, str):
        return False
    
    if len(subject) > MAX_SUBJECT_LENGTH:
        return False
    
    return True

def sanitize_string(value: str, max_length: int = None) -> str:
    if not isinstance(value, str):
        return str(value)
    
    sanitized = value.strip()
    
    if max_length and len(sanitized) > max_length:
        sanitized = sanitized[:max_length]
    
    return sanitized

def validate_required_fields(data: Dict[str, Any], notification_type: str) -> bool:
    required_fields = NOTIFICATION_TYPES[notification_type]['required_fields']
    
    for field in required_fields:
        if field not in data or not data[field]:
            return False
    
    return True

def build_message_attributes(notification_type: str, metadata: Dict[str, Any]) -> Dict[str, Any]:
    attributes = {
        'notification_type': {
            'DataType': 'String',
            'StringValue': notification_type
        }
    }
    
    allowed_metadata_keys = ['severity', 'source', 'error_code', 'environment', 'service']
    
    if metadata:
        for key, value in metadata.items():
            if key in allowed_metadata_keys and isinstance(value, str):
                sanitized_value = sanitize_string(value, 256)
                attributes[key] = {
                    'DataType': 'String',
                    'StringValue': sanitized_value
                }
    
    return attributes

def publish_to_sns(topic_arn: str, message: str, subject: str, message_attributes: Dict[str, Any]) -> Dict[str, Any]:
    try:
        response = sns_client.publish(
            TopicArn=topic_arn,
            Message=message,
            Subject=subject,
            MessageAttributes=message_attributes
        )
        
        return {
            'success': True,
            'message_id': response['MessageId']
        }
    except Exception as e:
        error_message = str(e)
        if 'topic' in error_message.lower() or 'arn' in error_message.lower():
            error_message = 'Failed to publish message: Invalid topic configuration'
        
        return {
            'success': False,
            'error': error_message
        }

def lambda_handler(event, context):
    try:
        if isinstance(event.get('body'), str):
            body = json.loads(event['body'])
        else:
            body = event
        
        topic_arn = body.get('topic_arn', '').strip()
        notification_type = body.get('notification_type', '').strip().lower()
        message_content = body.get('message', '')
        subject = body.get('subject', '')
        metadata = body.get('metadata', {})
        
        if not validate_topic_arn(topic_arn):
            return {
                'statusCode': 403,
                'body': json.dumps({
                    'error': 'Invalid or unauthorized topic ARN'
                })
            }
        
        if not validate_notification_type(notification_type):
            return {
                'statusCode': 400,
                'body': json.dumps({
                    'error': f'Invalid notification type. Allowed types: {list(NOTIFICATION_TYPES.keys())}'
                })
            }
        
        if not validate_required_fields(body, notification_type):
            required_fields = NOTIFICATION_TYPES[notification_type]['required_fields']
            return {
                'statusCode': 400,
                'body': json.dumps({
                    'error': f'Missing required fields for {notification_type}: {required_fields}'
                })
            }
        
        if not validate_message_content(message_content):
            return {
                'statusCode': 400,
                'body': json.dumps({
                    'error': 'Invalid message content or message too large'
                })
            }
        
        sanitized_message = sanitize_string(message_content)
        
        if not subject:
            subject_prefix = NOTIFICATION_TYPES[notification_type]['subject_prefix']
            subject = f"{subject_prefix} Notification"
        
        sanitized_subject = sanitize_string(subject, MAX_SUBJECT_LENGTH)
        
        if not validate_subject(sanitized_subject):
            return {
                'statusCode': 400,
                'body': json.dumps({
                    'error': 'Invalid subject'
                })
            }
        
        message_attributes = build_message_attributes(notification_type, metadata)
        
        result = publish_to_sns(
            topic_arn=topic_arn,
            message=sanitized_message,
            subject=sanitized_subject,
            message_attributes=message_attributes
        )
        
        if result['success']:
            return {
                'statusCode': 200,
                'body': json.dumps({
                    'message': 'Notification published successfully',
                    'message_id': result['message_id'],
                    'notification_type': notification_type
                })
            }
        else:
            return {
                'statusCode': 500,
                'body': json.dumps({
                    'error': result['error']
                })
            }
    
    except json.JSONDecodeError:
        return {
            'statusCode': 400,
            'body': json.dumps({
                'error': 'Invalid JSON in request body'
            })
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': 'Internal server error'
            })
        }